# tests/test_text_utils.py
from myapp.text_utils import truncate, count_tokens, slugify

def test_truncate_returns_full_string_when_short_enough():
    result = truncate("hello world", max_length=20)
    assert result == "hello world"

def test_truncate_adds_ellipsis_when_too_long():
    result = truncate("hello world", max_length=8)
    assert result == "hello..."
    assert len(result) == 8

def test_truncate_empty_string():
    result = truncate("", max_length=10)
    assert result == ""

def test_slugify_converts_spaces_to_hyphens():
    assert slugify("Hello World") == "hello-world"

def test_slugify_removes_special_chars():
    assert slugify("Hello, World!") == "hello-world"

def test_count_tokens_empty_string():
    assert count_tokens("") == 0

def test_count_tokens_single_word():
    # rough token estimate: 1 word ≈ 1 token for short English words
    count = count_tokens("hello")
    assert count >= 1

# tests/conftest.py  (shared fixtures for the test suite)
import pytest
from myapp.models import User, Address

@pytest.fixture
def alice():
    """A standard user fixture used across multiple test modules."""
    return User(
        id=1,
        name="Alice",
        email="alice@example.com",
        balance=100.00,
    )

@pytest.fixture
def alice_with_address(alice):
    """Extends the alice fixture with an address."""
    alice.address = Address(
        street="123 Main St",
        city="Springfield",
        country="US",
    )
    return alice

# tests/test_user.py — using the fixtures
from myapp.user_service import charge_user, format_shipping_label

def test_charge_user_reduces_balance(alice):
    charge_user(alice, amount=30.00)
    assert alice.balance == pytest.approx(70.00)

def test_charge_user_raises_on_insufficient_funds(alice):
    with pytest.raises(ValueError, match="Insufficient funds"):
        charge_user(alice, amount=200.00)

def test_format_shipping_label_includes_name_and_city(alice_with_address):
    label = format_shipping_label(alice_with_address)
    assert "Alice" in label
    assert "Springfield" in label
